#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAXN 100005
int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}
int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    int A[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    int ans = 0;
    for (int i = 0; i < Q; i++) {
        int ai, bi, ci, di, ki;
        scanf("%d %d %d %d %d", &ai, &bi, &ci, &di, &ki);
        int li = (ai * (ans > 0 ? ans : 0) + bi) % N + 1;
        int ri = (ci * (ans > 0 ? ans : 0) + di) % N + 1;
        if (li > ri) {
            int temp = li;
            li = ri;
            ri = temp;
        }
        int temp[ri - li + 1];
        int idx = 0;
        for (int j = li - 1; j < ri; j++) {
            temp[idx++] = A[j];
        }
        qsort(temp, idx, sizeof(int), compare);
        int unique[idx];
        int unique_idx = 0;
        for (int j = 0; j < idx; j++) {
            if (j == 0 || temp[j] != temp[j - 1]) {
                unique[unique_idx++] = temp[j];
            }
        }
        if (ki <= unique_idx) {
            ans = unique[ki - 1];
        } else {
            ans = -1;
        }
        printf("%d\n", ans);
    }
    return 0;
}

